mapper.select:
SELECT id,brand,license,model,code,displacement,status,type, color,kilometers,reg_time,buy_time,price,battery_type, geofence_bind_status,geofence_id,create_time,update_time FROM vehicle
id=#{id}
AND brand LIKE CONCAT('%',#{brand},'%')
AND license LIKE CONCAT('%',#{license},'%')
AND geofence_bind_status=#{geofenceBindStatus}
AND geofence_id=#{geofenceId}
ORDER BY create_time DESC

mapper.update:
UPDATE vehicle
brand=#{brand}, license=#{license}, model=#{model}, code=#{code}, displacement=#{displacement}, type=#{type}, color=#{color}, kilometers=#{kilometers}, buy_time=#{buyTime}, reg_time=#{regTime}, update_time=#{updateTime}, price=#{price}, battery_type=#{batteryType}, geofence_bind_status=#{geofenceBindStatus}, geofence_id=#{geofenceId}, status=#{status}
WHERE id=#{id}

UPDATE vehicle

    update_time=#{updateTime},
    geofence_bind_status=#{geofenceBindStatus},
    geofence_id=#{geofenceId}

WHERE id=#{id}
